'use client'

import { useEffect, useState } from 'react'
import Link from 'next/link'
import { Building2, Plus, Check, Trash2, Pencil } from 'lucide-react'
import { toast } from 'sonner'
import { PageHeader } from '@/components/dashboard/PageHeader'

interface Business {
  id: string
  companyName: string
  voiceDescription: string
  preferredPlatforms: string
  isActive: boolean
  updatedAt: string
}

export default function BusinessesPage() {
  const [businesses, setBusinesses] = useState<Business[]>([])
  const [isLoading, setIsLoading] = useState(true)

  async function load() {
    setIsLoading(true)
    try {
      const res = await fetch('/api/businesses')
      if (res.ok) {
        const data = await res.json()
        setBusinesses(data.businesses || [])
      }
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    load()
  }, [])

  async function activate(id: string) {
    try {
      const res = await fetch(`/api/businesses/${id}/activate`, { method: 'POST' })
      if (!res.ok) throw new Error('Failed to switch')
      toast.success('Active business updated')
      await load()
    } catch {
      toast.error('Failed to switch business')
    }
  }

  async function remove(id: string, name: string) {
    if (!confirm(`Delete "${name}"? This cannot be undone.`)) return
    try {
      const res = await fetch(`/api/businesses/${id}`, { method: 'DELETE' })
      if (!res.ok) throw new Error('Failed to delete')
      toast.success('Business profile deleted')
      await load()
    } catch {
      toast.error('Failed to delete business')
    }
  }

  return (
    <div className="max-w-5xl mx-auto px-8 py-8">
      <PageHeader
        eyebrow="MULTI-BRAND"
        title="Businesses"
        description="Manage multiple brand profiles. The agent uses whichever business is marked active for planning cycles."
        action={
          <Link href="/businesses/new" className="btn btn-primary h-10 px-5 text-sm flex items-center gap-2">
            <Plus className="w-4 h-4" />
            Add Business
          </Link>
        }
      />

      {isLoading ? (
        <div className="card p-12 text-center text-[#71717a]">Loading businesses...</div>
      ) : businesses.length === 0 ? (
        <div className="card p-12 text-center">
          <Building2 className="w-10 h-10 mx-auto text-[#3f3f46] mb-4" />
          <div className="font-medium text-lg mb-2">No business profiles yet</div>
          <p className="text-sm text-[#71717a] mb-6 max-w-sm mx-auto">
            Create your first profile so the agent knows your brand voice, audience, and goals.
          </p>
          <Link href="/businesses/new" className="btn btn-primary">
            Create First Business
          </Link>
        </div>
      ) : (
        <div className="grid gap-4">
          {businesses.map((biz) => (
            <div
              key={biz.id}
              className={`card p-6 transition-colors ${biz.isActive ? 'border-blue-500/30 bg-blue-500/5' : 'hover:border-[#3f3f46]'}`}
            >
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-semibold text-lg">{biz.companyName}</h3>
                    {biz.isActive && (
                      <span className="px-2 py-0.5 rounded-full bg-emerald-500/10 text-emerald-400 text-[10px] font-medium flex items-center gap-1">
                        <Check className="w-3 h-3" /> ACTIVE
                      </span>
                    )}
                  </div>
                  <p className="text-sm text-[#71717a] line-clamp-2">{biz.voiceDescription}</p>
                  <div className="text-xs text-[#52525b] mt-2">{biz.preferredPlatforms}</div>
                </div>

                <div className="flex items-center gap-2 shrink-0">
                  {!biz.isActive && (
                    <button onClick={() => activate(biz.id)} className="btn btn-secondary h-9 px-3 text-xs">
                      Set Active
                    </button>
                  )}
                  <Link href={`/businesses/${biz.id}`} className="btn btn-ghost h-9 px-3 text-xs border border-[#27272a]">
                    <Pencil className="w-3.5 h-3.5" />
                    Edit
                  </Link>
                  <button
                    onClick={() => remove(biz.id, biz.companyName)}
                    className="btn btn-ghost h-9 px-3 text-xs border border-[#27272a] text-red-400 hover:text-red-300"
                  >
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

import { redirect } from 'next/navigation'

export default function CalendarRedirect() {
  redirect('/content-studio/calendar')
}

'use client'

import { useEffect, useState } from 'react'
import { formatDistanceToNow } from 'date-fns'
import { RefreshCw } from 'lucide-react'
import { PageHeader } from '@/components/dashboard/PageHeader'

interface ActivityLog {
  id: string
  type: string
  summary: string
  timestamp: string
  contentItem?: { platform: string; format: string; title: string | null } | null
}

export default function ActivityPage() {
  const [logs, setLogs] = useState<ActivityLog[]>([])
  const [isLoading, setIsLoading] = useState(true)

  async function load() {
    setIsLoading(true)
    try {
      const res = await fetch('/api/activity?limit=50')
      if (res.ok) {
        const data = await res.json()
        setLogs(data.logs || [])
      }
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    load()
  }, [])

  return (
    <div className="max-w-4xl mx-auto px-8 py-8">
      <PageHeader
        eyebrow="CONTENT STUDIO"
        title="Activity"
        description="Immutable audit trail of agent decisions, approvals, and content generation."
      />

      <div className="flex justify-end mb-4">
        <button onClick={load} className="btn btn-ghost h-9 px-3 text-xs border border-[#27272a]">
          <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
          Refresh
        </button>
      </div>

      {isLoading ? (
        <div className="card p-12 text-center text-[#71717a]">Loading activity...</div>
      ) : logs.length === 0 ? (
        <div className="card p-12 text-center text-[#71717a]">No activity yet.</div>
      ) : (
        <div className="space-y-2">
          {logs.map((log) => (
            <div key={log.id} className="card p-4 flex items-start gap-4">
              <div className="w-2 h-2 rounded-full bg-blue-500 mt-2 shrink-0" />
              <div className="flex-1 min-w-0">
                <div className="text-sm font-medium">{log.summary}</div>
                <div className="flex flex-wrap gap-2 mt-1 text-[10px] text-[#52525b]">
                  <span className="px-2 py-0.5 rounded bg-[#27272a]">{log.type.replace(/_/g, ' ')}</span>
                  <span>{formatDistanceToNow(new Date(log.timestamp), { addSuffix: true })}</span>
                  {log.contentItem && (
                    <span>
                      {log.contentItem.platform} · {log.contentItem.format}
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameDay } from 'date-fns'
import { ChevronLeft, ChevronRight } from 'lucide-react'
import { PageHeader } from '@/components/dashboard/PageHeader'

interface CalendarItem {
  id: string
  platform: string
  format: string
  title: string | null
  body: string
  status: string
  scheduledFor: string | null
}

export default function CalendarPage() {
  const [items, setItems] = useState<CalendarItem[]>([])
  const [month, setMonth] = useState(new Date())

  useEffect(() => {
    fetch('/api/content?limit=100')
      .then((r) => r.json())
      .then((d) => setItems(d.items || []))
      .catch(() => setItems([]))
  }, [])

  const days = eachDayOfInterval({
    start: startOfMonth(month),
    end: endOfMonth(month),
  })

  const scheduled = items.filter(
    (i) =>
      i.scheduledFor &&
      ['APPROVED', 'SCHEDULED', 'READY_TO_PUBLISH', 'PUBLISHED'].includes(i.status)
  )

  return (
    <div className="max-w-5xl mx-auto px-8 py-8">
      <PageHeader
        eyebrow="CONTENT STUDIO"
        title="Calendar"
        description="Scheduled and approved content across your marketing calendar."
      />

      <div className="flex items-center justify-between mb-6">
        <button
          onClick={() => setMonth((m) => new Date(m.getFullYear(), m.getMonth() - 1, 1))}
          className="btn btn-ghost h-9 w-9 p-0"
        >
          <ChevronLeft className="w-4 h-4" />
        </button>
        <h2 className="text-lg font-semibold">{format(month, 'MMMM yyyy')}</h2>
        <button
          onClick={() => setMonth((m) => new Date(m.getFullYear(), m.getMonth() + 1, 1))}
          className="btn btn-ghost h-9 w-9 p-0"
        >
          <ChevronRight className="w-4 h-4" />
        </button>
      </div>

      <div className="grid grid-cols-7 gap-2 mb-8">
        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((d) => (
          <div key={d} className="text-center text-[10px] uppercase tracking-widest text-[#52525b] py-2">
            {d}
          </div>
        ))}
        {Array.from({ length: days[0].getDay() }).map((_, i) => (
          <div key={`pad-${i}`} />
        ))}
        {days.map((day) => {
          const dayItems = scheduled.filter(
            (item) => item.scheduledFor && isSameDay(new Date(item.scheduledFor), day)
          )
          return (
            <div
              key={day.toISOString()}
              className={`card min-h-[88px] p-2 ${isSameDay(day, new Date()) ? 'border-blue-500/40' : ''}`}
            >
              <div className="text-xs text-[#71717a] mb-1">{format(day, 'd')}</div>
              {dayItems.map((item) => (
                <div
                  key={item.id}
                  className="text-[10px] px-1.5 py-0.5 rounded bg-blue-500/10 text-blue-300 truncate mb-0.5"
                  title={item.title || item.body}
                >
                  {item.platform}
                </div>
              ))}
            </div>
          )
        })}
      </div>

      <div className="card p-6">
        <h3 className="text-sm font-medium mb-4">Upcoming scheduled content</h3>
        {scheduled.length === 0 ? (
          <p className="text-sm text-[#71717a]">Approve content to see it on the calendar.</p>
        ) : (
          <div className="space-y-3">
            {scheduled
              .sort(
                (a, b) =>
                  new Date(a.scheduledFor!).getTime() - new Date(b.scheduledFor!).getTime()
              )
              .slice(0, 10)
              .map((item) => (
                <div key={item.id} className="flex items-center justify-between text-sm border-b border-[#27272a] pb-3 last:border-0">
                  <div>
                    <span className="text-[#71717a] text-xs mr-2">
                      {item.scheduledFor
                        ? format(new Date(item.scheduledFor), 'MMM d, h:mm a')
                        : '—'}
                    </span>
                    <span className="font-medium">{item.title || item.body.slice(0, 60)}</span>
                  </div>
                  <span className="text-[10px] px-2 py-0.5 rounded bg-[#27272a]">{item.platform}</span>
                </div>
              ))}
          </div>
        )}
      </div>
    </div>
  )
}

import { redirect } from 'next/navigation'

export default function ContentStudioPage() {
  redirect('/content-studio/generate')
}
